#include <print>
#include <string>
#include <unordered_map>

class Solution
{
public:
    std::string minWindow(std::string s, std::string t)
    {
        auto expected_chars = std::unordered_map<char, int>();
        auto current_chars = std::unordered_map<char, int>();
        int best_start = -1, best_len = 1200000;
        std::string result{};

        for (char character : t)
        {
            ++expected_chars[character];
        }

        int covered_chars{0};

        for (int pa{0}, pb{0}; pb < s.size(); ++pb)
        {
            char character = s[pb];

            if (expected_chars.contains(character))
            {
                ++current_chars[character];
                if (current_chars[character] == expected_chars[character])
                    ++covered_chars;
            }

            while (covered_chars >= expected_chars.size())
            {
                if (pb - pa + 1 < best_len)
                {
                    best_len = pb - pa + 1;
                    best_start = pa;
                }

                char character_pa = s[pa];
                --current_chars[character_pa];

                if (expected_chars.contains(character_pa) && (current_chars[character_pa] < expected_chars[character_pa]))
                    --covered_chars;

                ++pa;
            }
        }

        return best_start == -1 ? "" : std::string(s.begin() + best_start, s.begin() + best_start + best_len);
    }
};

auto main() -> int
{
    std::string s = "";

    // std::string s = "aa";
    // std::string t = "aa";
    std::string t = "aAbBcCdDeEfFgGhHiIjJkKlLmMnNoOpPqQrRsStTuUvVwWxXyYzZ";

    auto result = Solution().minWindow(s, t);
    std::println("{}", result);
}
